// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'Reopen') {
        if (g_form.getValue('active') != 'false') {
            return false;
        }

        if (isNotActiveParent()) {
            return false;
        }

        if (isClosedTooLong()) {
            return false;
        }

        if (g_scratchpad.calchaschildren == 0) {
            // Do not show a modal; returning true allows the UI Action, Reopen Task, to execute server script
			return true;
        } else {
            confirmReopenTasks();
			return false;
        }
    }
}

// Use this function to show either a widget or UI Page modal
function confirmReopenTasks() {
    var messageTitle = getMessage('Tasker - Title - Reopen Selection');

    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_reopen_tasks_prompt',
            widgetInput: {
                'taskId': g_form.getUniqueValue()
            },
            buttons: [],
            // Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
            footerStyle: {
                'display': 'none'
            }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
        var gm = new GlideModal('x_153465_discovert_reopen_task_prompt');
        gm.setTitle(messageTitle);
        gm.setPreference('sysparm_taskSysId', g_form.getUniqueValue());
        gm.setWidth(550);
        gm.render();
    }
}

function isClosedTooLong() {
    var result = false;

    // STRY0016025- RAJ 2019-04-20 - Determine if Tasker close date is beyond the allowable reopen days
    if (g_scratchpad.closed_to_long_to_reopen == 'true' || g_scratchpad.closed_to_long_to_reopen == true) {
        g_form.addErrorMessage(g_form.getValue('number') + ' ' + getMessage('Tasker - Closed too long to reopen 1') + ' ' +
            g_scratchpad.ReopenMaxDays + ' ' + getMessage('Tasker - Closed too long to reopen 2') + ' ' + g_scratchpad.closed_at +
            getMessage('Tasker - Closed too long to reopen 3'));

        result = true;
    }

    return result;
}

// Task State 3 = Completed; 4 = Closed Incomplete; 7 = Cancelled should have active = 'false'
function isNotActiveParent() {
    var result = false;

    if (g_scratchpad.parent_sys_id + '' != '' && g_scratchpad.parent_active != 'true') {
        var link = "?id=discovertasker_taskdetails&sys_id=" + g_scratchpad.parent_sys_id +
            "&table=x_153465_discovert_route_task_instance&view=sp&state=3&order=1";

        g_form.addErrorMessage(" <b>" + getMessage('Tasker - Reopen Parent is not active - start') + " " + '<a href=' + link + '>' +
            g_scratchpad.parent_number + '</a>' + ' ' + getMessage('Tasker - Reopen Parent is not active - end') + '</b>');

        result = true;
    }

    return result;
}
